import{_ as e,c as i,a,o as n}from"./app-CEcM0piI.js";const l={};function d(t,s){return n(),i("div",null,s[0]||(s[0]=[a(`<p><strong>协变：</strong> 和谐的变化，自然的变化</p><p>因为里氏替换原则父类可以装子类，所以子类变父类感受是和谐的 比如 string 变成 object</p><p><strong>逆变：</strong> 逆常规的变化，不正常的变化 因为里氏替换原则父类可以装子类但是子类不能装父类，所以父类变子类感受是不和谐的 比如 object 变成 string</p><p>协变和逆变是用来修饰泛型占位符的 协变：out 逆变：in</p><p>用于在泛型中修饰泛型占位符的，只有泛型接口和泛型委托能使用</p><ul><li>使用out修饰的泛型只能作为返回值</li><li>使用in修饰的泛型只能作为参数</li></ul><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span></span></span>
<span class="line"><span>namespace Test</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>  delegate T TestOut&lt;out T&gt;();</span></span>
<span class="line"><span>  delegate void TestIn&lt;in T&gt;(T t);</span></span>
<span class="line"><span>  class Father { }</span></span>
<span class="line"><span>  class Son : Father { }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  class Program</span></span>
<span class="line"><span>  {</span></span>
<span class="line"><span>    static void Main()</span></span>
<span class="line"><span>    {</span></span>
<span class="line"><span>      // 协变：父类装子类</span></span>
<span class="line"><span>      TestOut&lt;Son&gt; os = () =&gt;</span></span>
<span class="line"><span>      {</span></span>
<span class="line"><span>        return new Son();</span></span>
<span class="line"><span>      };</span></span>
<span class="line"><span></span></span>
<span class="line"><span>      TestOut&lt;Father&gt; of = os;</span></span>
<span class="line"><span>      Father f = of();</span></span>
<span class="line"><span></span></span>
<span class="line"><span>      // 逆变：子类装父类</span></span>
<span class="line"><span>      TestIn&lt;Father&gt; iF = (value) =&gt; { };</span></span>
<span class="line"><span>      TestIn&lt;Son&gt; iS=iF;</span></span>
<span class="line"><span>      iS(new Son());</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p>加上out后的委托函数可以直接使用父类对象接收子类对象（协变） 加上in后的委托函数可以将子类对象传入到接收父类对象的参数中（逆变）</p><h1 id="多线程" tabindex="-1"><a class="header-anchor" href="#多线程"><span>多线程</span></a></h1><ol><li>创建线程</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Thread t=new Thread(任务函数)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="2"><li>启动线程 线程不启动是不会执行任务函数的</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>t.Start()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="3"><li>设置后台线程 默认创建的进程是前台进程，里面的任务不执行完毕无法关闭程序</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>t.IsBackground=true</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>将线程设置成后台线程后关闭进程这个线程也会被关闭</p><ol start="4"><li>终止线程</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>t.Abort()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="5"><li>休眠线程 在哪个线程中执行休眠的就是哪个线程，单位：毫秒</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Thread.Sleep();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="锁" tabindex="-1"><a class="header-anchor" href="#锁"><span>锁</span></a></h3><p>执行完lock的作用域块内的代码后会自动开锁</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>lock(obj){</span></span>
<span class="line"><span></span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="预处理器指令" tabindex="-1"><a class="header-anchor" href="#预处理器指令"><span>预处理器指令</span></a></h1><p>预处理器指令指导编译器在实际编译开始之前对信息进行预处理 预处理器指令都是以#开始 预处理器指令不是语句，所以它们不以分号；结束</p><ul><li>折叠代码块</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#region</span></span>
<span class="line"><span>#endregion</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>定义</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#define</span></span>
<span class="line"><span>#undef</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>判断</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#if</span></span>
<span class="line"><span>#elif</span></span>
<span class="line"><span>#else</span></span>
<span class="line"><span>#endif</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>提示</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#warning</span></span>
<span class="line"><span>#error</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="特性" tabindex="-1"><a class="header-anchor" href="#特性"><span>特性</span></a></h1><p>特性是一种允许我们向程序的程序集添加元数据的语言结构，它是用于保存程序结构信息的某种特殊类型的类 特性提供功能强大的方法以将声明信息与C#代码（类型、方法、属性等）相关联。 特性与程序实体关联后，即可在运行时使用反射查询特性信息 特性的目的是告诉编译器把程序结构的某组元数据嵌入程序集中，它可以放置在几乎所有的声明中（类、变量、函数等等申明）</p><p>特性本质是个类，我们可以利用特性类为元数据添加额外信息，比如一个类、成员变量、成员方法等等为他们添加更多的额外信息之后可以通过反射来获取这些额外信息</p><p>特性也就是装饰器，注解</p><h2 id="自定义特性" tabindex="-1"><a class="header-anchor" href="#自定义特性"><span>自定义特性</span></a></h2><p>自定义特性需要写一个类，这个类必须继承Attribute 命名一般是特性的功能+Attribute 在使用时会默认省略掉Attribute</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>  class MyCustomAttribute : Attribute</span></span>
<span class="line"><span>  {</span></span>
<span class="line"><span>    public string info;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    public MyCustomAttribute(string info)</span></span>
<span class="line"><span>    {</span></span>
<span class="line"><span>      this.info = info;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  [MyCustom(&quot;info&quot;)]</span></span>
<span class="line"><span>  class MyClass { }</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="使用" tabindex="-1"><a class="header-anchor" href="#使用"><span>使用</span></a></h3><p>在使用时使用反射机制判断一个对象上是否带有某个特性 参数一：特性的类型 参数二：是否搜索继承链（属性和事件忽略此参数）</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>if(t.IsDefined(typeof(MyCustomAttribute),false)){</span></span>
<span class="line"><span>	Console.WriteLine(&quot;该类型应用了MyCustomAttribute特性&quot;);</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="用法" tabindex="-1"><a class="header-anchor" href="#用法"><span>用法</span></a></h3><p>在类、函数、变量上面一行写上表示他们具有该特性</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>[特性名(参数列表)]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>传递给特性的参数也就是传递个声明这个特性类的构造函数</p><h3 id="限制" tabindex="-1"><a class="header-anchor" href="#限制"><span>限制</span></a></h3><p>为自定义特性限制使用范围</p><ul><li>AttributeTargets一特性能够用在哪些地方</li><li>AllowMultiple一是否允许多个特性实例用在同一个目标上</li><li>Inherited一特性是否能被派生类和重写成员继承</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>[AttributeUsage(AttributeTargets.Class | AttributeTargets.Struct,AllowMultiple =true,Inherited =true)]</span></span>
<span class="line"><span>class MyCustomAttribute : Attribute{}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="常用特性" tabindex="-1"><a class="header-anchor" href="#常用特性"><span>常用特性</span></a></h2><table><thead><tr><th>特性</th><th>作用</th></tr></thead><tbody><tr><td>Obsolete</td><td>提示用户该成员已经过时</td></tr><tr><td>CallerFilePath/LineNumber/MemberName</td><td>调用者信息：哪个文件/行/函数调用的</td></tr><tr><td>Conditional</td><td>条件编译特性，作用于函数上只有传入的符号被预处理指令#define定义过的调用被修饰的函数时，这个函数才会被执行</td></tr><tr><td>DllImport</td><td>标记非C#语言的函数，表明该函数是在外部的dll包中定义的，调用其他语言写的dll包（如c，c++）时使用</td></tr></tbody></table><h1 id="迭代器" tabindex="-1"><a class="header-anchor" href="#迭代器"><span>迭代器</span></a></h1><p>使用foreach基于范围的for循环的类都是实现了GetEnumerator,current，next，reset等函数 通常实现这个函数都是继承IEnumerable类，但不继承这个类直接实现GetEnumerator也会被foreach识别 current，next，reset函数在IEnumertor中 也就是要实现一个拥有迭代器的类就要继承IEnumerable和IEnumertor并实现其中的函数</p><h3 id="使用yield-return实现迭代器" tabindex="-1"><a class="header-anchor" href="#使用yield-return实现迭代器"><span>使用yield return实现迭代器</span></a></h3><p>使用yield return实现迭代器就不用实现current，next，reset函数了，只实现GetEnumerator就行</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public IEnumerator GetEnumerator(){</span></span>
<span class="line"><span>	for(int i=0;i&lt;list.Length;i++){</span></span>
<span class="line"><span>		yield return list[i];</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>yield return暂时返回保留当前的状态 使用yield return实现迭代器编译器会自动生成current，next，reset</p><h1 id="特殊语法" tabindex="-1"><a class="header-anchor" href="#特殊语法"><span>特殊语法</span></a></h1><h1 id="var" tabindex="-1"><a class="header-anchor" href="#var"><span>var</span></a></h1><p>可变类型，相当于c++中的auto 使用var声明的变量必须立即赋值，不能用作类的成员变量声明 主要作用就是偷懒</p><h2 id="匿名类型" tabindex="-1"><a class="header-anchor" href="#匿名类型"><span>匿名类型</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>var v=new {name=&quot;w&quot;,age=10}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="可空类型" tabindex="-1"><a class="header-anchor" href="#可空类型"><span>可空类型</span></a></h2><p>值类型不可为null，但是设置可空类型就可以赋值为null了</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int? a=null</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>GetValueOrDefault获取可空类型的值或默认值，int默认值为0，布尔为false... 也可以传入参数指定默认值</p><p>引用类型也可以使用可空类型</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>o?.ToString()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>使用?.运算符判断前面的对象是否为空，如果为空后面的函数就不会被执行，如果不为空后面的函数就会执行</p><h2 id="空合并操作符" tabindex="-1"><a class="header-anchor" href="#空合并操作符"><span>空合并操作符</span></a></h2><p>?? 如果左边值不为空就返回左边值，否则返回右边值</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int a=v??100;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="模板字符串" tabindex="-1"><a class="header-anchor" href="#模板字符串"><span>模板字符串</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>string a=$&quot;nihao{1+2}&quot;;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div>`,76)]))}const p=e(l,[["render",d]]),h=JSON.parse('{"path":"/game/cs/4/","title":"4 进阶","lang":"zh-CN","frontmatter":{"title":"4 进阶","createTime":"2025/04/05 12:12:26","permalink":"/game/cs/4/"},"readingTime":{"minutes":5.32,"words":1596},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/游戏/C#/4 进阶.md","headers":[]}');export{p as comp,h as data};
